import std.money;
import nation as nation;

key id int;
property id.name string;
property id.address string;
property id.phone string;
property id.account_balance float::usd;
property id.market_segment string;
property id.comment string;

datasource customers (
    c_custkey:id,
    c_name:name,
    c_address:address,
    c_nationkey:nation.id,
    c_phone:phone,
    c_acctbal:account_balance,
    c_mktsegment:market_segment,
    c_comment:comment
)
grain (id)
address memory.customer;

import customer as customer;
import lineitem as lineitem;
import nation as nation;
import order as order;
import part as part;
import region as region;
import supplier as supplier;

import std.money;
import std.display;
import order as order;
import supplier as supplier;
import part as part;

key line_no int;
property <line_no,order.id>.row_key string;
property <line_no,order.id>.quantity float;
property <line_no,order.id>.extended_price float::usd;
property <line_no,order.id>.discount float::percent;
property <line_no,order.id>.tax float::percent;
property <line_no,order.id>.return_flag string;
property <line_no,order.id>.line_status string;
property <line_no,order.id>.ship_date date;
property <line_no,order.id>.commit_date date;
property <line_no,order.id>.receipt_date date;
property <line_no,order.id>.ship_instruct string;
property <line_no,order.id>.ship_mode string;
property <line_no,order.id>.comment string;
property revenue <- extended_price * (1 - discount);
property customer_charged <- revenue * (1 + tax);
metric total_revenue <- sum(revenue);

datasource lineitem (
    l_linenumber: line_no,
    l_orderkey: order.id,
    l_partkey: part.id,
    l_suppkey: supplier.id,
    concat(CAST(order.id AS string),'-',CAST(line_no AS string)): row_key,
    l_quantity: quantity,
    l_extendedprice: extended_price,
    l_discount: discount,
    l_tax: tax,
    l_returnflag: return_flag,
    l_linestatus: line_status,
    l_shipdate: ship_date,
    l_commitdate: commit_date,
    l_receiptdate: receipt_date,
    l_shipinstruct: ship_instruct,
    l_shipmode: ship_mode,
    l_comment: comment
)
grain (line_no,order.id)
address memory.lineitem;

import std.geography;
import region as region;

key id int;
property id._raw_name string;
property id.name string::country;
property id.comment string;

datasource nation (
    n_nationkey:id,
    n_name: _raw_name,
    UPPER(_raw_name):name,
    n_regionkey:region.id,
    n_comment:comment
)
grain(id)
address memory.nation;

import std.money;
import customer as customer;

key id int;
property id.status string;
property id.total_price float::usd;
property id.date date;
property id.priority string;
property id.clerk string;
property id.ship_priority int;
property id.comment string;

datasource orders (
    o_orderkey: id,
    o_custkey: ~customer.id,
    o_orderstatus: status,
    o_totalprice: total_price,
    o_orderdate: date,
    o_orderpriority: priority,
    o_clerk: clerk,
    o_comment: comment,
    o_shippriority: ship_priority
)
grain (id)
address memory.orders;

import std.money;
import supplier as supplier;

key id int;
property id._name string;
property id.name string;
property id.manufacturer string;
property id.brand string;
property id.type string;
property id.size int;
property id.container string;
property id.retail_price float::usd;
property id.comment string;

datasource part (
    p_partkey:id,
    p_name:_name,
    UPPER(_name):name,
    p_mfgr: manufacturer,
    p_brand:brand,
    p_type:type,
    p_size:size,
    p_container:container,
    p_retailprice:retail_price,
    p_comment:comment
)
grain(id)
address memory.part;

property <id,supplier.id>.available_quantity float;
property <id,supplier.id>.supply_cost float::usd;
property <id,supplier.id>.supplier_comment string;

datasource partsupp (
    ps_partkey:id,
    ps_suppkey:supplier.id,
    ps_availqty: available_quantity,
    ps_supplycost:supply_cost,
    ps_comment:supplier_comment
)
grain (id, supplier.id)
address memory.partsupp;

key id int;
property id.name string;
property id.comment string;

datasource region (
    r_regionkey:id,
    r_name:name,
    r_comment:comment
)
grain(id)
address memory.region;

import nation as nation;
import std.money;

key id int;
property id.name string;
property id.address string;
property id.phone string;
property id.account_balance numeric(12,5)::usd;
property id.comment string;

datasource supplier (
    s_suppkey:id,
    s_name:name,
    s_address:address,
    s_nationkey:nation.id,
    s_phone:phone,
    s_acctbal:account_balance,
    s_comment:comment
)
grain (id)
address memory.supplier;

import lineitem as line_item;
import std.display;

auto discounted_price <- line_item.extended_price * (1-line_item.discount);
auto charge_price <- discounted_price * (1+line_item.tax);

def part_percent_of_nation(x) -> cast(sum(x) by line_item.part.name, line_item.supplier.nation.id / sum(x) by line_item.supplier.nation.id as float::percent);

WHERE line_item.ship_date <= '1998-12-01'::date
SELECT
    line_item.part.name,
    line_item.supplier.nation.name,
    sum(charge_price)-> total_charge_price,
    sum(discounted_price) -> total_discounted_price,
    @part_percent_of_nation(charge_price) as charge_price_percent_of_nation,
    @part_percent_of_nation(discounted_price) as discount_price_percent_of_nation
ORDER BY
    total_charge_price desc limit 100
;
